import React, { useState, useEffect } from "react";
import {
  signUpWithEmail,
  loginWithEmail,
  signInWithGoogle,
  logout,
  monitorAuthState,
  resetPassword,
} from "../firebase";
import { motion, AnimatePresence } from "framer-motion";
import { Eye, EyeOff, Loader2 } from "lucide-react";
import logo from "../assets/logo.png";

export default function Home() {
  const [isLogin, setIsLogin] = useState(true);
  const [user, setUser] = useState(null);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [showSplash, setShowSplash] = useState(true);

  // Simulated splash screen
  useEffect(() => {
    const timer = setTimeout(() => setShowSplash(false), 2500);
    return () => clearTimeout(timer);
  }, []);

  // Monitor auth state
  useEffect(() => {
    const unsubscribe = monitorAuthState(setUser);
    return unsubscribe;
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (isLogin) {
        await loginWithEmail(email, password);
      } else {
        await signUpWithEmail(email, password);
      }
    } catch (err) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleGoogle = async () => {
    setLoading(true);
    try {
      await signInWithGoogle();
    } catch (err) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleForgotPassword = async () => {
    if (!email) {
      alert("Please enter your email to reset password.");
      return;
    }
    try {
      await resetPassword(email);
      alert("Password reset link sent to your email.");
    } catch (err) {
      alert(err.message);
    }
  };

  const handleLogout = async () => {
    await logout();
  };

  return (
    <div className="min-h-screen flex flex-col bg-gradient-to-br from-black via-gray-900 to-gray-800 text-white font-sans">
      {/* Splash Screen */}
      <AnimatePresence>
        {showSplash && (
          <motion.div
            initial={{ opacity: 1 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0, scale: 1.1 }}
            transition={{ duration: 1 }}
            className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50"
          >
            <motion.img
              src={logo}
              alt="Godemar’s Empire"
              className="w-24 h-24 mb-4"
              initial={{ opacity: 0, y: 40 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 1 }}
            />
            <motion.h1
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.5 }}
              className="text-2xl font-semibold text-yellow-400 tracking-wide"
            >
              Godemar’s Empire
            </motion.h1>
          </motion.div>
        )}
      </AnimatePresence>

      {!showSplash && (
        <>
          {/* Hero Section */}
          <motion.header
            initial={{ opacity: 0, y: -30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.7 }}
            className="flex flex-col items-center justify-center py-14 px-6 text-center"
          >
            <h1 className="text-2xl md:text-5xl font-bold text-yellow-400 mb-3">
              The Grand Coordinating Enterprise
            </h1>
            <p className="text-md md:text-lg text-gray-300 max-w-2xl">
              Connecting creators, innovators, and dreamers. A hub for collaboration and opportunity.
            </p>
          </motion.header>

          {/* Auth Section */}
          <motion.section
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.6 }}
            className="flex flex-col items-center justify-center flex-grow px-6"
          >
            {!user ? (
              <div className="w-full max-w-md bg-gray-900 rounded-2xl shadow-2xl p-8 border border-gray-800">
                <h2 className="text-2xl font-semibold text-center mb-6 text-yellow-400">
                  {isLogin ? "Login to Continue" : "Create Your Account"}
                </h2>

                <form onSubmit={handleSubmit} className="space-y-4">
                  <input
                    type="email"
                    placeholder="Email Address"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                    className="w-full p-3 rounded-md bg-gray-800 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-yellow-500"
                  />
                  <div className="relative">
                    <input
                      type={showPassword ? "text" : "password"}
                      placeholder="Password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      required
                      className="w-full p-3 rounded-md bg-gray-800 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-yellow-500"
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-3 text-gray-400 hover:text-yellow-400"
                    >
                      {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                    </button>
                  </div>

                  <button
                    type="submit"
                    disabled={loading}
                    className="w-full py-3 bg-yellow-500 text-black font-semibold rounded-md hover:bg-yellow-400 transition flex items-center justify-center"
                  >
                    {loading ? (
                      <>
                        <Loader2 className="animate-spin mr-2" size={20} />
                        Processing...
                      </>
                    ) : isLogin ? (
                      "Login"
                    ) : (
                      "Sign Up"
                    )}
                  </button>
                </form>

                <button
                  onClick={handleGoogle}
                  disabled={loading}
                  className="w-full py-3 mt-4 border border-yellow-500 text-yellow-500 font-medium rounded-md hover:bg-yellow-500 hover:text-black transition flex items-center justify-center"
                >
                  {loading ? (
                    <>
                      <Loader2 className="animate-spin mr-2" size={20} />
                      Connecting...
                    </>
                  ) : (
                    "Continue with Google"
                  )}
                </button>

                <div className="flex justify-between text-sm text-gray-400 mt-4">
                  <button onClick={handleForgotPassword} className="hover:underline">
                    Forgot Password?
                  </button>
                  <button
                    onClick={() => setIsLogin(!isLogin)}
                    className="text-yellow-400 hover:underline"
                  >
                    {isLogin ? "Create Account" : "Login Instead"}
                  </button>
                </div>
              </div>
            ) : (
              <div className="text-center space-y-6">
                <h2 className="text-3xl font-semibold text-yellow-400">
                  Welcome, {user.email}
                </h2>
                <p className="text-gray-300">
                  You’re now logged in to Godemar’s Empire community.
                </p>
                <button
                  onClick={handleLogout}
                  className="px-6 py-3 bg-yellow-500 text-black rounded-lg hover:bg-yellow-400 transition"
                >
                  Logout
                </button>
              </div>
            )}
          </motion.section>

          <footer className="bg-black py-6 mt-12 text-center text-gray-500 text-sm border-t border-gray-800">
            © {new Date().getFullYear()} Godemar’s Empire. All rights reserved.
          </footer>
        </>
      )}
    </div>
  );
}
